import React, { useCallback, useEffect, useRef, useState } from 'react'
import { i18n } from '@fs/zion-locale'
import { Alert, Separator } from '@fs/zion-ui'
import { geoData } from '@fs/zion-config'
import { Person } from '@fs/zion-icon'

import useGeoLocation from '../../../../components/Map/hooks/useGeoLocation'
import Marker from '../Marker/Marker' // Internal Only Marker
import Center from '../Center'
import { useChildrenBoundsApi } from '../../../../components/Map/hooks/useChildrenBounds'

const DELAY_DURATION_MS = 50

export default function UserLocation({ setClickHandler }) {
  const [geoLocationBlocked, setGeoLocationBlocked] = useState(false)
  const [userLocation, setUserLocation] = useState()
  const { geoLocation } = useGeoLocation()
  const { skipNextFitToChildrenRef } = useChildrenBoundsApi()
  const markerRef = useRef()
  const firstRenderRef = useRef(true)

  const onGeoLocationBlocked = useCallback(() => {
    const rawLatitude = geoData?.latitude ?? window?.SERVER_DATA?.geoData?.latitude ?? geoLocation?.latitude
    const rawLongitude = geoData?.longitude ?? window?.SERVER_DATA?.geoData?.longitude ?? geoLocation?.longitude

    if (rawLatitude === null || rawLatitude === undefined || rawLongitude === null || rawLongitude === undefined) {
      setGeoLocationBlocked(true)

      return
    }

    const latitude = Number(rawLatitude)
    const longitude = Number(rawLongitude)

    const isValidLatitude = !Number.isNaN(latitude) && latitude >= -90 && latitude <= 90
    const isValidLongitude = !Number.isNaN(longitude) && longitude >= -180 && longitude <= 180

    if (!isValidLatitude || !isValidLongitude) {
      setGeoLocationBlocked(true)

      return
    }

    setUserLocation({ latitude, longitude })
  }, [geoLocation])

  // Set up click handler to get user location
  useEffect(() => {
    function onSuccess(currentPosition) {
      skipNextFitToChildrenRef.current = true

      const currentUserLocation = {
        latitude: currentPosition.coords.latitude,
        longitude: currentPosition.coords.longitude,
      }
      setUserLocation(currentUserLocation)
    }

    function onFailure() {
      onGeoLocationBlocked()
    }

    function clickHandler() {
      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(onSuccess, onFailure)
        markerRef.current?.openInfo()
      } else {
        onFailure()
      }
    }

    setClickHandler(() => clickHandler)
  }, [onGeoLocationBlocked, setClickHandler, skipNextFitToChildrenRef])

  return (
    <>
      {userLocation && (
        <Marker
          ariaLabel={i18n.t('map.marker.yourLocation', 'Your Location')}
          Icon={Person}
          info={i18n.t('map.marker.yourLocation', 'Your Location')}
          latitude={userLocation.latitude}
          longitude={userLocation.longitude}
          ref={(ref) => {
            if (ref && markerRef.current !== ref) {
              markerRef.current = ref
              if (firstRenderRef.current) {
                firstRenderRef.current = false

                // Give a short delay to allow the marker to be rendered and positioned before opening the info.
                setTimeout(() => {
                  markerRef.current.openInfo()
                }, DELAY_DURATION_MS)
              }
            }
          }}
        />
      )}
      {geoLocationBlocked && (
        <Center>
          <Alert dismissable onDismiss={() => setGeoLocationBlocked(false)} type="warning">
            {'geolocation' in navigator
              ? i18n.t(
                  'map.block-geolocation.error',
                  'Your browser is blocking this site from accessing your location.'
                )
              : i18n.t('map.no-geolocation.error', "Your browser doesn't support accessing your location.")}
            <Separator size="nano" />
            {i18n.t('map.block-geolocation.note', 'This feature will not work until you allow access.')}
          </Alert>
        </Center>
      )}
    </>
  )
}
