import React, { forwardRef, lazy, Suspense } from 'react'
import PropTypes from 'prop-types'

import useMap from '../hooks/useMap'
import { draggableDirectionsValidator } from './draggableDirectionsConstraints'

const AzureMarker = lazy(() => import('../../AzureMap/Marker/Marker'))
const BingMarker = lazy(() => import('../../BingMap/Marker/Marker'))
const GoogleMarker = lazy(() => import('../../GoogleMap/Marker/Marker'))

const Marker = forwardRef(
  (
    {
      ariaLabel,
      chars,
      cluster, // Internal Only
      color = 'red',
      draggable = false,
      draggableDirections, // Internal Only
      focused = false,
      Icon,
      id, // Internal Only
      imageSrc,
      info,
      label,
      latitude,
      longitude,
      metadata,
      onBlur,
      onClick,
      onDrag, // Internal Only
      onDragEnd,
      onFocus,
      onInfoClosed,
      onMouseEnter,
      onMouseLeave,
      proximity, // Internal Only
      testId,
      title, // Internal Only
    },
    ref
  ) => {
    const { azure, bing } = useMap()

    const props = {
      ariaLabel,
      chars,
      cluster, // Internal Only
      color: color ?? 'red',
      draggable,
      draggableDirections, // Internal Only
      focused,
      Icon,
      id, // Internal Only
      imageSrc,
      info,
      label,
      latitude,
      longitude,
      metadata,
      onBlur,
      onClick,
      onDrag, // Internal Only
      onDragEnd,
      onFocus,
      onInfoClosed,
      onMouseEnter,
      onMouseLeave,
      proximity, // Internal Only
      testId,
      title, // Internal Only
    }

    return (
      <Suspense fallback={null}>
        {azure && !bing && <AzureMarker {...props} ref={ref} />}
        {bing && <BingMarker {...props} ref={ref} />}
        {!azure && !bing && <GoogleMarker {...props} ref={ref} />}
      </Suspense>
    )
  }
)

Marker.displayName = 'Marker'

export default Marker

Marker.propTypes = {
  ariaLabel: PropTypes.string.isRequired,
  chars: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  /**
   * Internal Only
   *
   * Whether to render the marker as a cluster marker.
   */
  cluster: PropTypes.bool,
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),
  draggable: PropTypes.bool,
  /**
   * Internal Only
   *
   * The directions in which the marker can be dragged.
   */
  draggableDirections: draggableDirectionsValidator,
  focused: PropTypes.bool,
  Icon: PropTypes.func,
  /**
   * Internal Only
   *
   * This ID is used to identify clustered markers that are continuously added and removed.
   */
  id: PropTypes.string,
  imageSrc: PropTypes.string,
  info: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  label: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  latitude: PropTypes.number.isRequired,
  longitude: PropTypes.number.isRequired,
  metadata: PropTypes.any,
  onBlur: PropTypes.func,
  onClick: PropTypes.func,
  /**
   * Internal Only
   *
   * The callback to run during marker drag.
   */
  onDrag: PropTypes.func,
  onDragEnd: PropTypes.func,
  onFocus: PropTypes.func,
  onInfoClosed: PropTypes.func,
  onMouseEnter: PropTypes.func,
  onMouseLeave: PropTypes.func,
  /**
   * Internal Only
   *
   * Whether to render the marker as a proximity marker.
   */
  proximity: PropTypes.bool,
  testId: PropTypes.string,
  /**
   * Internal Only
   *
   * The title to use for the marker.
   *
   * This will be used as the `title` attribute on the marker element.
   * Prefer using `label` unless it makes sense to use `title`.
   * The `aria-label` attribute is used for accessibility so `title` is not needed for accessibility purposes.
   */
  title: PropTypes.string,
}
