import React, { useEffect, useState } from 'react'
import { i18n } from '@fs/zion-locale'
import { css, cx } from '@linaria/core'
import { ControlFullscreen, ControlFullscreenExit } from '@fs/zion-icon'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'

import useMap from '../hooks/useMap'

const fullscreenControlClassName = css`
  inset-block-start: 100px;
  inset-inline-end: 0px;
  position: absolute;
`

const buttonClassName = css`
  background-color: ${rawDayColors.gray['00']};
  border: none;
  border-radius: 2px;
  box-shadow: rgba(0, 0, 0, 0.3) 0px 1px 4px -1px;
  color: #666666;
  margin: 10px;
  padding: 8px;
  pointer-events: auto;
  position: relative;
  z-index: 3;

  &:hover {
    color: #333333;
  }
`

export default function FullscreenControl({ bing }) {
  const [isFullscreen, setIsFullscreen] = useState(false)
  const { fullscreenContainer, nonInteractive } = useMap()

  useEffect(() => {
    function handleFullscreenChange() {
      setIsFullscreen(
        Boolean(
          document.fullscreenElement ||
          document.webkitFullscreenElement ||
          document.mozFullScreenElement ||
          document.msFullscreenElement
        )
      )
    }

    document.addEventListener('fullscreenchange', handleFullscreenChange)

    return () => {
      document.removeEventListener('fullscreenchange', handleFullscreenChange)
    }
  }, [])

  if (nonInteractive) {
    return null
  }

  function toggleFullscreen() {
    if (isFullscreen) {
      if (document.exitFullscreen) {
        document.exitFullscreen()
      } else if (document.mozCancelFullScreen) {
        document.mozCancelFullScreen()
      } else if (document.msExitFullscreen) {
        document.msExitFullscreen()
      } else if (document.webkitExitFullscreen) {
        document.webkitExitFullscreen()
      }
    } else if (fullscreenContainer.requestFullscreen) {
      fullscreenContainer.requestFullscreen()
    } else if (fullscreenContainer.mozRequestFullScreen) {
      fullscreenContainer.mozRequestFullScreen()
    } else if (fullscreenContainer.msRequestFullscreen) {
      fullscreenContainer.msRequestFullscreen()
    } else if (fullscreenContainer.webkitRequestFullscreen) {
      fullscreenContainer.webkitRequestFullscreen()
    }
  }

  return (
    <div className={cx(bing && fullscreenControlClassName)}>
      <button
        aria-label={i18n.t('map.fullscreen-control.toggle', 'Toggle fullscreen view')}
        className={buttonClassName}
        onClick={toggleFullscreen}
        title={i18n.t('map.fullscreen-control.toggle', 'Toggle fullscreen view')}
        type="button"
      >
        {isFullscreen ? <ControlFullscreenExit /> : <ControlFullscreen />}
      </button>
    </div>
  )
}
